B.TD=new A.y(B.I,"Modal fiiller zorunluluk ve izin ifade eder",'Modal fiiller, **zorunluluk derecelerini** ifade etti\u011fi i\xe7in havac\u0131l\u0131k \u0130ngilizcesinde son derece \xf6nemlidir. "must" ile "should" aras\u0131ndaki fark g\xfcvenlik sonu\xe7lar\u0131 do\u011furabilir.\n\n**must** = zorunlu (yasal gereklilik)\n**should** = \xf6nerilen (en iyi uygulama)\n**may** = izin verilen (serbest)\n**can** = yetenek / teorik olas\u0131l\u0131k',null,null,null)
B.UK=new A.y(B.fd,"Modal g\xfc\xe7 skalas\u0131",null,null,B.tb,null)
B.X4=new A.y(B.w,"Modal + Fiil Yap\u0131s\u0131",'**Rule:** Modal verb + **base infinitive** (no "to", no "-s", no "-ing")\n\n\u2713 The pilot **must check** the fuel level.\n\u2717 The pilot must **checks** / must **checking** / must **to check**\n\n**With passive:**\nModal + **be** + past participle\n\u2713 The engine **must be shut down** before maintenance.\n\u2713 Parts **should be inspected** visually.',null,null,null)
B.NK=new A.a5("The engine must be shut down before any maintenance work begins.","Herhangi bir bak\u0131m \xe7al\u0131\u015fmas\u0131 ba\u015flamadan \xf6nce motor kapat\u0131lmal\u0131d\u0131r.","must be shut down")
B.PJ=new A.a5("Technicians should wear protective equipment when handling fuel.","Teknisyenler yak\u0131t ile \xe7al\u0131\u015f\u0131rken koruyucu ekipman takmal\u0131d\u0131r.","should wear")
B.OR=new A.a5("The aircraft may depart after all checks are completed.","T\xfcm kontroller tamamland\u0131ktan sonra u\xe7ak kalkabilir.","may depart")
B.ON=new A.a5("Contaminated parts must not be reinstalled without inspection.","Kirlenmi\u015f par\xe7alar incelenmeden yeniden tak\u0131lmamal\u0131d\u0131r.","must not be reinstalled")
B.a1a=s([B.NK,B.PJ,B.OR,B.ON],t.l)
