B.WA=new A.y(B.am,"\u2708\ufe0f S\u0131nav \u0130pucu","Zaman belirte\xe7leri kipe i\u015faret eder:\n\u2022 **now / currently / at the moment** \u2192 \u015fimdiki s\xfcrekli zaman\n\u2022 **always / usually / every flight** \u2192 basit geni\u015f zaman\n\u2022 **at 14:32 / yesterday / last night** \u2192 basit ge\xe7mi\u015f zaman\n\u2022 **while / when / as** \u2192 iki e\u015f zamanl\u0131 ge\xe7mi\u015f eylem aray\u0131n\n\nHavac\u0131l\u0131k kay\u0131tlar\u0131 ve raporlar her zaman **basit ge\xe7mi\u015f zaman** kullan\u0131r \u2014 tamamlanm\u0131\u015f olaylar\u0131 kaydederler.",null,null,null)
