B.a4D=s(["Direct source of good lighting","Inspection aids such as mirrors","Complete disassembly of the aircraft","Surface cleaning"],t.s)
B.ad4=new A.P(-71,B.af,602,"Which of the following is NOT necessarily required for a Detailed Inspection?",B.a4D,2,B.t,null,null,null)
B.a6v=s(["An entire aircraft at once","The aircraft's documentation","A specific item, installation, or assembly","Only the exterior of the aircraft"],t.s)
