B.aee=new A.P(-312,B.af,652,"What action permanently eliminates the need for repetitive inspections?",B.a09,1,B.t,null,null,null)
B.a5w=s(["Before the next annual check","Within 100 flight cycles after the effective date","Before the next 500 flight cycles","At first opportunity after receiving the AD"],t.s)
B.acy=new A.P(-313,B.af,653,"The first inspection must be completed:",B.a5w,1,B.r,null,null,null)
