B.TX=new A.y(B.I,"\u0130\u015f emri sistemi neden \xf6\u011frenilmeli","Work Order (WO) ve Job Card (JC/Task Card), bak\u0131m planlamas\u0131 ve takibinin temelini olu\u015fturur. Part-145 onayl\u0131 organizasyonlarda t\xfcm bak\u0131m faaliyetleri bir i\u015f emrine ba\u011fl\u0131d\u0131r.\n\nBir i\u015f emrini do\u011fru okumak: i\u015fin kapsam\u0131n\u0131, kullan\u0131lacak referans dok\xfcmanlar\u0131, gerekli par\xe7a ve ekipman\u0131 ve imza yetkinliklerini anlamay\u0131 gerektirir.",null,null,null)
