B.TP=new A.y(B.I,"Transponder neden \xf6nemlidir?",'Transponder, u\xe7a\u011f\u0131n radar ekran\u0131nda ATC taraf\u0131ndan tan\u0131nmas\u0131n\u0131 sa\u011flar. ATC her u\xe7a\u011fa \xf6zg\xfc bir "squawk" (transponder kodu) verir. Do\u011fru kodu girmek ve ATC talimatlar\u0131n\u0131 anlamak trafi\u011fin g\xfcvenli y\xf6netimi i\xe7in zorunludur.',null,null,null)
