B.W5=new A.y(B.I,"Anormal kontrol listelerinin sabit dil kal\u0131plar\u0131 vard\u0131r","Motor ar\u0131zas\u0131 ve di\u011fer anormal/acil durum kontrol listeleri havac\u0131l\u0131ktaki en kesin dili kullan\u0131r. Bu alandan gelen bo\u015fluk doldurma sorular\u0131 hem teknik bilgiyi hem de kelime do\u011frulu\u011funu s\u0131nar.\n\nDo\u011fru prosed\xfcr fiili kritik \xf6neme sahiptir \u2014 yanl\u0131\u015f eylem kelimesi kullanmak havac\u0131l\u0131kta asla kabul edilemez.",null,null,null)
B.Tv=new A.y(B.w,"\ud83d\udd25 Motor Ar\u0131zas\u0131 Kelime Bilgisi","**Thrust lever** \u2014 controls engine power (throttle)\n**Fuel control lever** \u2014 starts/stops fuel to engine\n**Engine fire handle** \u2014 emergency shut-off and fire suppression control\n**HP fuel cock / Shutoff valve** \u2014 high-pressure fuel control\n**N1 / N2** \u2014 fan speed (%) / core speed (%)\n**EGT** \u2014 Exhaust Gas Temperature\n**ITT** \u2014 Interstage Turbine Temperature\n**Surge** \u2014 compressor stall; loud bang, rpm fluctuation",null,null,null)
