B.OW=new A.a5("In the event of an engine fire, the crew must pull the engine fire handle.","Motor yang\u0131n\u0131 durumunda ekip, motor yang\u0131n kolunu \xe7ekmelidir.","pull the engine fire handle")
B.Pm=new A.a5("If the fire is not extinguished, discharge the second fire extinguisher agent.","Yang\u0131n s\xf6nd\xfcr\xfclemezse ikinci s\xf6nd\xfcr\xfcc\xfc maddesini de\u015farj edin.","discharge")
B.Pw=new A.a5("Cross-check the affected engine number before taking any action.","Herhangi bir i\u015flem yapmadan \xf6nce etkilenen motor numaras\u0131n\u0131 \xe7apraz kontrol edin.","Cross-check")
