B.OJ=new A.a5('"The landing may be continued provided that the reported RVR is not less than 550 metres."',"Bildirilen RVR 550 metreden az olmad\u0131\u011f\u0131 s\xfcrece ini\u015f s\xfcrd\xfcr\xfclebilir.","provided that \u2026 is not less than")
