B.X1=new A.y(B.I,"Kaza raporlar\u0131 kesin hukuki ve teknik dil kullan\u0131r","ICAO Ek 13 kaza ara\u015ft\u0131rma raporlar\u0131, havac\u0131l\u0131ktaki en dilbilimsel a\xe7\u0131dan zorlay\u0131c\u0131 belgeler aras\u0131ndad\u0131r. Tek bir metinde hukuki kesinli\u011fi, edilgen yap\u0131lar\u0131, teknik do\u011frulu\u011fu ve nedensellik analizini bir araya getirirler.\n\nBu raporlardan \xe7eviri sorular\u0131, hem teknik anlam\u0131 hem de her ifadenin hukuki sonu\xe7lar\u0131n\u0131 anlamay\u0131 gerektirir.",null,null,null)
B.Vr=new A.y(B.w,"\u26a0\ufe0f Nedensellik Dili",'**Probable cause** \u2014 the primary factor judged to have produced the accident\n**Contributing factor** \u2014 a condition that increased risk but was not the primary cause\n**Causal factor** \u2014 any element in the cause chain\n\nCausal verbs and phrases:\n\u2022 "**led to**" = caused/resulted in (direct chain)\n\u2022 "**attributed to**" = judged as the cause\n\u2022 "**resulted in**" = produced this outcome\n\u2022 "**was a factor in**" = contributed but not sole cause\n\u2022 "**was consistent with**" = evidence matches this explanation',null,null,null)
B.XN=new A.y(B.w,"\ud83d\udccb Soru\u015fturma Bulgular\u0131 Dili",'"The investigation **found** that\u2026" \u2192 formal finding\n"Evidence **indicated** that\u2026" \u2192 supported but not proven\n"**It could not be determined** whether\u2026" \u2192 insufficient evidence\n"The crew **failed to**\u2026" \u2192 did not perform required action\n"**Contrary to** the standard operating procedure\u2026" \u2192 SOP violation\n"The accident **is survivable** / **was not survivable**" \u2192 survivability finding\n"**Safety recommendation**" \u2192 formal advisory to prevent recurrence',null,null,null)
B.PI=new A.a5("The probable cause of the accident was the crew's failure to monitor fuel quantity.","Kazan\u0131n muhtemel nedeni, ekibin yak\u0131t miktar\u0131n\u0131 izlememesiydi.","probable cause")
B.P1=new A.a5("It could not be determined whether the crew had received the updated weather information.","Ekibin g\xfcncellenmi\u015f hava durumu bilgisini al\u0131p almad\u0131\u011f\u0131 belirlenemedi.","It could not be determined")
